(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[8237],{1850:(e,a,n)=>{"use strict";n.r(a),n.d(a,{data:()=>s});const s={key:"v-88b8776e",path:"/python/module/",title:"Methods",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"Importing Library",slug:"importing-library",children:[{level:3,title:"โหลดทุก method ใน math",slug:"โหลดทุก-method-ใน-math",children:[]},{level:3,title:"โหลดบางตัว",slug:"โหลดบางตัว",children:[]}]}],filePathRelative:"python/module/README.md",git:{updatedTime:162676698e4,contributors:[]}}},2488:(e,a,n)=>{"use strict";n.r(a),n.d(a,{default:()=>t});const s=(0,n(6252).uE)('<h1 id="methods" tabindex="-1"><a class="header-anchor" href="#methods" aria-hidden="true">#</a> Methods</h1><blockquote><p>In computer science, a library is a collection of non-volatile resources used by computer programs, often for software development. These may include configuration data, documentation, help data, message templates, pre-written code and subroutines, classes, values or type specifications. -- Wikipedia.com</p></blockquote><p>ก็จะสรุปได้ว่า เป็น collection ที่มีฟังก์ชั่นที่เขียนไว้แล้ว ให้นักพัฒนาได้เอาไปใช้นั่นเอง</p><h2 id="importing-library" tabindex="-1"><a class="header-anchor" href="#importing-library" aria-hidden="true">#</a> Importing Library</h2><p>ถ้าน้องๆต้องการที่จะใช้ <code>library math</code> น้องๆก็จำเป็นที่ต้องโหลดมันซะก่อน โดยมีอยู่ 2 วิธีครับ</p><ul><li>โหลดตัว function ที่จะใช้จริง</li><li>โหลด function ทุกตัวที่อยู่ใน library</li></ul><p>แต่เนื่องจากว่า ถ้าน้องโหลดทุกตัวมา มันก็จะกินทรัพยากรเครื่องมากกว่า แต่ก็ไม่เป็นอะไรหรอกครับ ทรัพยากรเหลือเยอะแยะนะ อิอิ</p><h3 id="โหลดทุก-method-ใน-math" tabindex="-1"><a class="header-anchor" href="#โหลดทุก-method-ใน-math" aria-hidden="true">#</a> โหลดทุก method ใน <code>math</code></h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">import</span> math\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>หรือหากว่าน้องอยากที่จะเปลี่ยนชื่อ library ไปเป็นตามสไตล์ของน้องเอง ก็สามารถทำได้ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">import</span> math <span class="token keyword">as</span> quickmaffs\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>โดยคำว่า <code>as</code> นั้นจะทำให้น้องเปลี่ยนชื่อของ library ได้ทำให้น้องเรียก <code>quickmaffs.ceii()</code> แทน <code>math.ceil()</code> ได้ครับ</p><p>ตัวอย่างการใช้งาน function เมื่อโหลดมาแล้ว</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">print</span><span class="token punctuation">(</span>math<span class="token punctuation">.</span>ceil<span class="token punctuation">(</span><span class="token number">12.5</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>สังเกตว่าจะมีการเขียน <code>math</code> ไว้หน้าชื่อฟังก์ชั่นด้วยนะครับ</p><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>แต่เปลี่ยนแล้ว เปลี่ยนกลับไม่ได้นาจาา ยกเว้นว่าจะ import ใหม่ครับ</p></div><h3 id="โหลดบางตัว" tabindex="-1"><a class="header-anchor" href="#โหลดบางตัว" aria-hidden="true">#</a> โหลดบางตัว</h3><p>ใน ณ​ ตอนนี้อาจจะยังไม่ต้องเรียนก็ได้ครับ เพราะอันที่แล้วก็เพียงพอ แต่ถ้าอยากก็ไม่ว่าอะไรครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">from</span> math <span class="token keyword">import</span> ceil\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>สังเกตว่าชื่อ library อยู่ที่หลัง <code>from</code> และชื่อ function จะอยู่หลัง <code>import</code></p><p>ทำให้การเรียกใช้งานไม่ต้องมี <code>math.</code> แล้ว เรียกเหมือนฟังก์ชั่นธรรมดาได้เลย</p><p>ตัวอย่าง</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">print</span><span class="token punctuation">(</span>ceil<span class="token punctuation">(</span><span class="token number">12.5</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div>',23),t={render:function(e,a){return s}}}}]);